import SwiftUI
import AIUsagesTrackersLib

/// Scrollable popover anchored to the menu bar item; uses LazyVStack + maxHeight
/// so the popover does not stretch unboundedly when many accounts are present.
struct UsageDetailsView: View {
    let store: UsageStore
    let refreshState: RefreshState
    let onRefresh: () async -> Void
    let onQuit: () -> Void


    private static let maxPopoverHeight: CGFloat = 480
    private static let popoverWidth: CGFloat = 320

    var body: some View {
        let sorted = store.entries.sortedForDisplay()
        let multiVendors = store.entries.vendorsWithMultipleAccounts()

        VStack(spacing: 0) {
            if sorted.isEmpty {
                emptyState
            } else {
                ScrollView {
                    LazyVStack(spacing: 8) {
                        ForEach(sorted) { entry in
                            AccountCardView(
                                entry: entry,
                                showActiveBadge: multiVendors.contains(entry.vendor),
                                isRefreshing: refreshState.isRefreshing(
                                    vendor: entry.vendor,
                                    account: entry.account
                                )
                            )
                        }
                    }
                    .padding(12)
                }
                .frame(maxHeight: Self.maxPopoverHeight)
                .background(Color(NSColor.windowBackgroundColor).opacity(0.4))
            }

            Divider()

            footer
        }
        .frame(width: Self.popoverWidth)
    }

    // MARK: - Subviews

    private var emptyState: some View {
        VStack(spacing: 8) {
            Text("No usage data")
                .font(.system(size: 12, weight: .medium))
                .foregroundStyle(.secondary)
            Text("Waiting for data...")
                .font(.system(size: 11))
                .foregroundStyle(.tertiary)
        }
        .frame(maxWidth: .infinity)
        .padding(.vertical, 32)
    }

    private var footer: some View {
        let refreshing = !refreshState.inFlight.isEmpty
        return HStack(spacing: 8) {
            Text("AI Usages Tracker")
                .font(.system(size: 10))
                .foregroundStyle(.tertiary)
            Spacer()
            Button {
                guard !refreshing else { return }
                Task { await onRefresh() }
            } label: {
                ZStack {
                    if refreshing {
                        ProgressView()
                            .controlSize(.small)
                            .scaleEffect(0.6)
                    } else {
                        Image(systemName: "arrow.clockwise")
                    }
                }
                .frame(width: 16, height: 16)
            }
            .buttonStyle(.borderless)
            .controlSize(.small)
            .disabled(refreshing)
            .help("Refresh usage data")
            .keyboardShortcut("r")
            .focusable(false)

            Button("Quit") {
                onQuit()
            }
            .keyboardShortcut("q")
            .controlSize(.small)
            .focusable(false)
        }
        .padding(.horizontal, 12)
        .padding(.vertical, 8)
    }
}

import SwiftUI
import AIUsagesTrackersLib

/// Displays a time-window metric: name, gauge bar with theoretical marker,
/// percentage, remaining time, and next reset date.
struct TimeWindowMetricRow: View {
    let name: String
    let resetAt: ISODate
    let windowDuration: DurationMinutes
    let usagePercent: UsagePercent

    private var actualFraction: Double {
        Double(usagePercent.rawValue) / 100.0
    }

    var body: some View {
        let now = Date()
        let isExpired = resetAt.date.map { now > $0 } ?? false
        let theoretical = isExpired ? 0.0 : theoreticalFraction(resetAt: resetAt, windowDuration: windowDuration, now: now)
        let tier = consumptionRatio(actualPercent: usagePercent, theoreticalFraction: theoretical)
            .map(consumptionTier(ratio:))

        VStack(alignment: .leading, spacing: 4) {
            HStack {
                Text(name)
                    .font(.system(size: 11, weight: .medium))
                    .foregroundStyle(.secondary)
                Spacer()
                Text(isExpired ? "???" : "\(usagePercent.rawValue)%")
                    .font(.system(size: 11, weight: .semibold).monospacedDigit())
            }

            GaugeBar(
                actual: isExpired ? 0.0 : actualFraction,
                theoretical: theoretical,
                tier: tier
            )

            HStack {
                Text(isExpired ? "???" : formatRemainingTime(resetAt: resetAt, now: now))
                    .font(.system(size: 10).monospacedDigit())
                    .foregroundStyle(.secondary)
                Spacer()
                Text(isExpired ? "resets ???" : "resets \(formatResetDate(resetAt, now: now))")
                    .font(.system(size: 10))
                    .foregroundStyle(.secondary)
            }
        }
    }
}

import SwiftUI
import AIUsagesTrackersLib

/// showActiveBadge is resolved by the parent so each card doesn't re-scan the full entry list.
struct AccountCardView: View {
    let entry: VendorUsageEntry
    let showActiveBadge: Bool
    let isRefreshing: Bool

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack(spacing: 6) {
                Text(entry.vendor.rawValue.capitalized)
                    .font(.system(size: 12, weight: .semibold))

                Text(entry.account.rawValue)
                    .font(.system(size: 11))
                    .foregroundStyle(.secondary)
                    .lineLimit(1)
                    .truncationMode(.middle)

                if isRefreshing {
                    ProgressView()
                        .controlSize(.small)
                        .scaleEffect(0.6)
                        .frame(width: 12, height: 12)
                }

                Spacer()

                if showActiveBadge && entry.isActive {
                    Text("active")
                        .font(.system(size: 9, weight: .medium))
                        .foregroundStyle(.white)
                        .padding(.horizontal, 6)
                        .padding(.vertical, 2)
                        .background(Color.green, in: Capsule())
                }
            }

            ForEach(Array(entry.metrics.enumerated()), id: \.offset) { _, metric in
                metricRow(for: metric)
            }
        }
        .padding(10)
        .background(
            (showActiveBadge && entry.isActive)
                ? Color.green.opacity(0.20)
                : Color(NSColor.controlBackgroundColor),
            in: RoundedRectangle(cornerRadius: 8)
        )
        .overlay(
            RoundedRectangle(cornerRadius: 8)
                .strokeBorder(Color.primary.opacity(0.20), lineWidth: 1)
        )
    }

    @ViewBuilder
    private func metricRow(for metric: UsageMetric) -> some View {
        switch metric {
        case let .timeWindow(name, resetAt, windowDuration, usagePercent):
            TimeWindowMetricRow(
                name: name,
                resetAt: resetAt,
                windowDuration: windowDuration,
                usagePercent: usagePercent
            )
        case let .payAsYouGo(name, currentAmount, currency):
            PayAsYouGoMetricRow(
                name: name,
                currentAmount: currentAmount,
                currency: currency
            )
        case .unknown:
            EmptyView()
        }
    }
}

